import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { PianoKeyboard } from '../components/PianoKeyboard';

export const PianoPage = () => {
  const navigate = useNavigate();

  // selectedKey: the note the user last clicked, e.g. "C"
  const [selectedKey, setSelectedKey] = useState(null);

  // scaleNotes: the notes returned from the API, e.g. ["C","D","E","F","G","A","B"]
  // these are passed to PianoKeyboard so it knows which keys to highlight
  const [scaleNotes, setScaleNotes] = useState([]);

  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);

  const handleKeyClick = async (note) => {
    setSelectedKey(note);
    setLoading(true);
    setError(null);

    try {
      // encodeURIComponent handles sharps: "C#" → "C%23" so the URL is valid
      const res = await fetch(`http://localhost:8081/api/keys/${encodeURIComponent(note)}`);

      if (!res.ok) {
        throw new Error(`API returned ${res.status}`);
      }

      // API returns { key: "C", notes: ["C","D","E","F","G","A","B"] }
      const data = await res.json();
      setScaleNotes(data.notes);
    } catch (err) {
      setError('Could not reach the API. Is the backend running?');
      setScaleNotes([]);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="bg-background text-textMain font-sans antialiased min-h-screen flex flex-col items-center justify-center px-4 relative">

      {/* Back button */}
      <button
        onClick={() => navigate('/')}
        className="absolute top-8 left-8 px-4 py-2 rounded-full border border-white/20 hover:bg-white/10 transition-colors text-sm"
      >
        ← Back
      </button>

      <div className="text-center space-y-10 w-full max-w-2xl">

        {/* Title */}
        <div>
          <h1 className="font-display text-5xl font-bold mb-2">Piano</h1>
          <p className="text-textMuted text-lg">Click any key to see its major scale.</p>
        </div>

        {/* The keyboard widget */}
        {/* scaleNotes flows down from API response → into PianoKeyboard as highlightedNotes */}
        <div className="flex justify-center">
          <PianoKeyboard
            onKeyClick={handleKeyClick}
            highlightedNotes={scaleNotes}
          />
        </div>

        {/* Result panel — only shown after a key is clicked */}
        {selectedKey && (
          <div className="glass-panel rounded-2xl p-6 text-left">
            <p className="text-sm text-primary font-bold uppercase tracking-wider mb-4">
              {loading ? 'Loading...' : `Key of ${selectedKey} major`}
            </p>

            {error && (
              <p className="text-red-400 text-sm">{error}</p>
            )}

            {/* Each returned note rendered as a pill */}
            {!loading && !error && (
              <div className="flex flex-wrap gap-2">
                {scaleNotes.map((note) => (
                  <span
                    key={note}
                    className="px-4 py-2 rounded-full bg-primary/20 border border-primary/30 text-primary font-bold text-sm"
                  >
                    {note}
                  </span>
                ))}
              </div>
            )}
          </div>
        )}

      </div>
    </div>
  );
};
